export * from './message-scroller-button.component';
export * from './message-scroller-content.component';
export * from './message-scroller-item.component';
export * from './message-scroller-viewport.component';
export * from './message-scroller.component';
export * from './message-scroller.token';
export * from './message-scroller.imports';

import {
  ChangeDetectionStrategy,
  Component,
  computed,
  inject,
  input,
  ViewEncapsulation,
} from '@angular/core';
import { NgIcon, provideIcons } from '@ng-icons/core';
import { phosphorCaretDown } from '@ng-icons/phosphor-icons/regular';

import { cn, type ClassValue } from '{{alias}}/utils';
import { HB_MESSAGE_SCROLLER, type HbMessageScrollerContext } from './message-scroller.token';

@Component({
  selector: 'hb-message-scroller-button',
  imports: [NgIcon],
  viewProviders: [provideIcons({ phosphorCaretDown })],
  template: `
    <button
      type="button"
      [class]="buttonClasses()"
      [attr.data-visible]="visible() || null"
      [attr.aria-hidden]="!visible()"
      [tabindex]="visible() ? 0 : -1"
      aria-label="Scroll to latest messages"
      (click)="ctx.scrollToEnd(true)"
    >
      <ng-icon [name]="hbIcon()" />
    </button>
  `,
  changeDetection: ChangeDetectionStrategy.OnPush,
  encapsulation: ViewEncapsulation.None,
  host: {
    class: 'pointer-events-none absolute inset-x-0 bottom-4 z-10 flex justify-center',
    '[attr.data-slot]': "'message-scroller-button'",
  },
  exportAs: 'hbMessageScrollerButton',
})
export class HbMessageScrollerButtonComponent {
  protected readonly ctx = inject<HbMessageScrollerContext>(HB_MESSAGE_SCROLLER);

  readonly hbIcon = input('phosphorCaretDown');
  readonly class = input<ClassValue>('');

  protected readonly visible = computed(() => this.ctx.scrollableEnd());
  protected readonly buttonClasses = computed(() =>
    cn(
      'pointer-events-auto inline-flex size-9 items-center justify-center rounded-full border border-border bg-background text-foreground shadow-md transition-all hover:bg-accent',
      'opacity-0 translate-y-2 data-[visible]:translate-y-0 data-[visible]:opacity-100',
      !this.visible() && 'pointer-events-none',
      this.class(),
    ),
  );
}

import {
  ChangeDetectionStrategy,
  Component,
  computed,
  input,
  ViewEncapsulation,
} from '@angular/core';

import { cn, type ClassValue } from '{{alias}}/utils';

@Component({
  selector: 'hb-message-scroller-content',
  template: `<ng-content />`,
  changeDetection: ChangeDetectionStrategy.OnPush,
  encapsulation: ViewEncapsulation.None,
  host: {
    role: 'log',
    'aria-live': 'polite',
    'aria-relevant': 'additions',
    '[class]': 'classes()',
    '[attr.data-slot]': "'message-scroller-content'",
  },
  exportAs: 'hbMessageScrollerContent',
})
export class HbMessageScrollerContentComponent {
  readonly class = input<ClassValue>('');

  protected readonly classes = computed(() =>
    cn('flex flex-col gap-4 p-4', this.class()),
  );
}

import {
  booleanAttribute,
  ChangeDetectionStrategy,
  Component,
  DestroyRef,
  ElementRef,
  inject,
  input,
  ViewEncapsulation,
} from '@angular/core';

import { HB_MESSAGE_SCROLLER, type HbMessageScrollerItemRef } from './message-scroller.token';

@Component({
  selector: 'hb-message-scroller-item',
  template: `<ng-content />`,
  changeDetection: ChangeDetectionStrategy.OnPush,
  encapsulation: ViewEncapsulation.None,
  host: {
    '[attr.data-slot]': "'message-scroller-item'",
    '[attr.data-message-id]': 'hbMessageId() || null',
    '[attr.data-anchor]': 'hbScrollAnchor() || null',
  },
  exportAs: 'hbMessageScrollerItem',
})
export class HbMessageScrollerItemComponent {
  private readonly ctx = inject(HB_MESSAGE_SCROLLER);
  private readonly el = inject<ElementRef<HTMLElement>>(ElementRef);
  private readonly destroyRef = inject(DestroyRef);

  readonly hbMessageId = input('');
  readonly hbScrollAnchor = input(false, { transform: booleanAttribute });

  private readonly ref: HbMessageScrollerItemRef = {
    messageId: () => this.hbMessageId(),
    anchor: () => this.hbScrollAnchor(),
    element: () => this.el.nativeElement,
  };

  constructor() {
    this.ctx.registerItem(this.ref);
    this.destroyRef.onDestroy(() => this.ctx.unregisterItem(this.ref));
  }
}

import {
  afterNextRender,
  ChangeDetectionStrategy,
  Component,
  computed,
  DestroyRef,
  ElementRef,
  inject,
  input,
  ViewEncapsulation,
} from '@angular/core';

import { cn, type ClassValue } from '{{alias}}/utils';
import { HB_MESSAGE_SCROLLER, type HbMessageScrollerContext } from './message-scroller.token';

@Component({
  selector: 'hb-message-scroller-viewport',
  template: `<ng-content />`,
  changeDetection: ChangeDetectionStrategy.OnPush,
  encapsulation: ViewEncapsulation.None,
  host: {
    '[class]': 'classes()',
    '[attr.data-slot]': "'message-scroller-viewport'",
    '[attr.data-autoscrolling]': 'ctx.autoScrolling() ? "" : null',
    '[attr.data-scrollable]': 'scrollable()',
    '(scroll)': 'ctx.onViewportScroll()',
  },
  exportAs: 'hbMessageScrollerViewport',
})
export class HbMessageScrollerViewportComponent {
  protected readonly ctx = inject<HbMessageScrollerContext>(HB_MESSAGE_SCROLLER);
  private readonly host = inject<ElementRef<HTMLElement>>(ElementRef);
  private readonly destroyRef = inject(DestroyRef);

  readonly class = input<ClassValue>('');

  protected readonly classes = computed(() =>
    cn('min-h-0 flex-1 overflow-y-auto overscroll-contain', this.class()),
  );
  protected readonly scrollable = computed(() => {
    const start = this.ctx.scrollableStart();
    const end = this.ctx.scrollableEnd();
    if (start && end) return 'both';
    if (start) return 'start';
    if (end) return 'end';
    return null;
  });

  constructor() {
    afterNextRender(() => {
      const el = this.host.nativeElement;
      this.ctx.registerViewport(el);
      const RO = (globalThis as { ResizeObserver?: typeof ResizeObserver }).ResizeObserver;
      const ro = RO ? new RO(() => this.ctx.onContentResize()) : null;
      const target = el.firstElementChild ?? el;
      ro?.observe(target);
      this.destroyRef.onDestroy(() => ro?.disconnect());
    });
  }
}

import {
  booleanAttribute,
  ChangeDetectionStrategy,
  Component,
  computed,
  forwardRef,
  input,
  numberAttribute,
  signal,
  ViewEncapsulation,
} from '@angular/core';

import { cn, type ClassValue } from '{{alias}}/utils';
import {
  HB_MESSAGE_SCROLLER,
  type HbMessageScrollerContext,
  type HbMessageScrollerItemRef,
  type HbScrollPosition,
} from './message-scroller.token';

const AT_BOTTOM_THRESHOLD = 24;

@Component({
  selector: 'hb-message-scroller',
  template: `<ng-content />`,
  changeDetection: ChangeDetectionStrategy.OnPush,
  encapsulation: ViewEncapsulation.None,
  providers: [
    { provide: HB_MESSAGE_SCROLLER, useExisting: forwardRef(() => HbMessageScrollerComponent) },
  ],
  host: {
    '[class]': 'classes()',
    '[attr.data-slot]': "'message-scroller'",
  },
  exportAs: 'hbMessageScroller',
})
export class HbMessageScrollerComponent implements HbMessageScrollerContext {
  readonly hbAutoScroll = input(true, { transform: booleanAttribute });
  readonly hbDefaultScrollPosition = input<HbScrollPosition>('end');
  readonly hbScrollPreviousItemPeek = input(0, { transform: numberAttribute });
  readonly class = input<ClassValue>('');

  private readonly viewportEl = signal<HTMLElement | null>(null);
  private readonly items = signal<HbMessageScrollerItemRef[]>([]);
  private readonly engaged = signal(true);
  private readonly programmatic = signal(false);
  private readonly atBottomSig = signal(true);
  private readonly scrollStartSig = signal(false);
  private readonly scrollEndSig = signal(false);

  protected readonly classes = computed(() =>
    cn('relative flex min-h-0 flex-col overflow-hidden', this.class()),
  );

  readonly autoScroll = this.hbAutoScroll;
  readonly atBottom = this.atBottomSig.asReadonly();
  readonly scrollableStart = this.scrollStartSig.asReadonly();
  readonly scrollableEnd = this.scrollEndSig.asReadonly();
  readonly autoScrolling = this.programmatic.asReadonly();

  registerViewport(element: HTMLElement): void {
    this.viewportEl.set(element);
    const position = this.hbDefaultScrollPosition();
    if (position === 'start') {
      element.scrollTop = 0;
      this.engaged.set(false);
      this.measure();
    } else if (position === 'last-anchor') {
      const anchors = this.ordered().filter((i) => i.anchor());
      const last = anchors[anchors.length - 1];
      if (last) this.scrollToMessage(last.messageId(), false);
      else this.scrollToEnd(false);
    } else {
      this.scrollToEnd(false);
    }
  }

  registerItem(item: HbMessageScrollerItemRef): void {
    this.items.update((list) => [...list, item]);
  }
  unregisterItem(item: HbMessageScrollerItemRef): void {
    this.items.update((list) => list.filter((i) => i !== item));
  }

  onViewportScroll(): void {
    this.measure();
    if (!this.programmatic()) this.engaged.set(this.atBottomSig());
  }
  onContentResize(): void {
    if (this.hbAutoScroll() && this.engaged()) this.scrollToEnd(false);
    else this.measure();
  }

  scrollToEnd(smooth = true): void {
    const el = this.viewportEl();
    if (!el) return;
    this.programmatic.set(true);
    this.applyScroll(el, el.scrollHeight, smooth);
    this.engaged.set(true);
    this.atBottomSig.set(true);
    this.scrollEndSig.set(false);
    this.scrollStartSig.set(el.scrollTop > 1);
    this.clearProgrammatic();
  }
  scrollToStart(smooth = true): void {
    const el = this.viewportEl();
    if (!el) return;
    this.programmatic.set(true);
    this.applyScroll(el, 0, smooth);
    this.engaged.set(false);
    this.clearProgrammatic();
  }
  scrollToMessage(id: string, smooth = true): void {
    const el = this.viewportEl();
    const item = this.items().find((i) => i.messageId() === id);
    if (!el || !item) return;
    const target =
      el.scrollTop +
      item.element().getBoundingClientRect().top -
      el.getBoundingClientRect().top -
      this.hbScrollPreviousItemPeek();
    this.programmatic.set(true);
    this.applyScroll(el, Math.max(0, target), smooth);
    this.clearProgrammatic();
  }

  private applyScroll(el: HTMLElement, top: number, smooth: boolean): void {
    if (smooth && typeof el.scrollTo === 'function') el.scrollTo({ top, behavior: 'smooth' });
    else el.scrollTop = top;
  }

  private measure(): void {
    const el = this.viewportEl();
    if (!el) return;
    const dist = el.scrollHeight - el.clientHeight - el.scrollTop;
    this.atBottomSig.set(dist <= AT_BOTTOM_THRESHOLD);
    this.scrollStartSig.set(el.scrollTop > 1);
    this.scrollEndSig.set(dist > 1);
  }
  private ordered(): HbMessageScrollerItemRef[] {
    return [...this.items()].sort((a, b) =>
      a.element().compareDocumentPosition(b.element()) & Node.DOCUMENT_POSITION_FOLLOWING ? -1 : 1,
    );
  }
  private clearProgrammatic(): void {
    setTimeout(() => {
      this.programmatic.set(false);
      this.measure();
    }, 150);
  }
}

import { HbMessageScrollerButtonComponent } from './message-scroller-button.component';
import { HbMessageScrollerContentComponent } from './message-scroller-content.component';
import { HbMessageScrollerItemComponent } from './message-scroller-item.component';
import { HbMessageScrollerViewportComponent } from './message-scroller-viewport.component';
import { HbMessageScrollerComponent } from './message-scroller.component';

export const HbMessageScrollerImports = [
  HbMessageScrollerComponent,
  HbMessageScrollerViewportComponent,
  HbMessageScrollerContentComponent,
  HbMessageScrollerItemComponent,
  HbMessageScrollerButtonComponent,
] as const;

import { InjectionToken } from '@angular/core';

export type HbScrollPosition = 'start' | 'end' | 'last-anchor';

export interface HbMessageScrollerItemRef {
  messageId: () => string;
  anchor: () => boolean;
  element: () => HTMLElement;
}

export interface HbMessageScrollerContext {
  autoScroll: () => boolean;
  atBottom: () => boolean;
  scrollableStart: () => boolean;
  scrollableEnd: () => boolean;
  autoScrolling: () => boolean;
  registerViewport(element: HTMLElement): void;
  registerItem(item: HbMessageScrollerItemRef): void;
  unregisterItem(item: HbMessageScrollerItemRef): void;
  onViewportScroll(): void;
  onContentResize(): void;
  scrollToEnd(smooth?: boolean): void;
  scrollToStart(smooth?: boolean): void;
  scrollToMessage(id: string, smooth?: boolean): void;
}

export const HB_MESSAGE_SCROLLER = new InjectionToken<HbMessageScrollerContext>(
  'HB_MESSAGE_SCROLLER',
);

